import{_ as a,o as t,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"The Online Indicator","description":"","frontmatter":{},"headers":[],"relativePath":"reference/online-indicator.md","filePath":"reference/online-indicator.md"}'),n={name:"reference/online-indicator.md"};function r(l,e,s,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="the-online-indicator" tabindex="-1">The Online Indicator <a class="header-anchor" href="#the-online-indicator" aria-label="Permalink to &quot;The Online Indicator&quot;">​</a></h1><p>The online indicator is a quick presence hint on the <strong>Users</strong> pages. It helps you see whether someone was active very recently without opening audit logs or profile history.</p><blockquote><p>Screenshot placeholder: admin-users-online.png</p></blockquote><h2 id="what-online-means-here" tabindex="-1">What &quot;online&quot; means here <a class="header-anchor" href="#what-online-means-here" aria-label="Permalink to &quot;What &quot;online&quot; means here&quot;">​</a></h2><p>A user counts as online when their most recent activity was within the last 5 minutes.</p><p>That is why the indicator is only a recent-activity signal. It does not mean:</p><ul><li>they are looking at the same page as you</li><li>they are ready to reply right now</li><li>they have made a fresh change this second</li></ul><h2 id="what-you-may-see" tabindex="-1">What you may see <a class="header-anchor" href="#what-you-may-see" aria-label="Permalink to &quot;What you may see&quot;">​</a></h2><p>Depending on the user&#39;s recent activity, the interface can show:</p><ul><li><code>online now</code></li><li><code>seen ... ago</code></li><li><code>login ... ago</code></li><li><code>no login yet</code></li></ul><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><p>You will mainly notice it:</p><ul><li>in the <strong>Users</strong> list</li><li>on a user&#39;s profile area inside the assignments editor</li><li>in some admin and management lists that show responsible users</li></ul><h2 id="how-to-use-it-well" tabindex="-1">How to use it well <a class="header-anchor" href="#how-to-use-it-well" aria-label="Permalink to &quot;How to use it well&quot;">​</a></h2><ul><li>Use it as a quick clue, not as proof.</li><li>If a user looks inactive, check their broader account details before making a decision.</li><li>If someone never logged in, you may need to reset their password or confirm they received their account details.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../how-to/create-user.html">Create a User</a></li><li><a href="./../how-to/edit-user.html">Edit a User &amp; Reset Their Password</a></li><li><a href="./../getting-started/navigating.html">Finding Your Way Around</a></li></ul>',17)])])}const m=a(n,[["render",r]]);export{p as __pageData,m as default};
